#include <stdio.h>
#include <stdlib.h>
#include <errno.h>
#include <limits.h>
#include <string.h>

int main(int argc, char* argv[]) {
 if (argc != 2) {
 fprintf(stderr, "Usage: %s <number>\n", argv[0]);
 return 1;
 }

 char *endptr;
 errno = 0;

 // Convert string to long using strtol
 long num = strtol(argv[1], &endptr, 10);

 // Check for conversion errors
 if (errno == ERANGE) {
 fprintf(stderr, "Error: Number out of range\n");
 return 1;
 }

 if (endptr == argv[1]) {
 fprintf(stderr, "Error: No digits found\n");
 return 1;
 }

 if (*endptr != '\0') {
 fprintf(stderr, "Warning: Extra characters after number: %s\n", endptr);
 }

 printf("Successfully converted: %ld\n", num);
 return 0;
}

