#include <stdio.h>
#include <unistd.h>
#include <stdlib.h>

int main(int argc, char *argv[]) {
 int opt;
 int verbose = 0;
 char *filename = NULL;

 // Options: h=help, v=verbose, f=filename (requires argument)
 while ((opt = getopt(argc, argv, "hvf:")) != -1) {
 switch (opt) {
 case 'h':
 printf("Usage: %s [-h] [-v] [-f <filename>]\n", argv[0]);
 printf(" -h Show help message\n");
 printf(" -v Enable verbose mode\n");
 printf(" -f Specify filename\n");
 return 0;
 case 'v':
 verbose = 1;
 break;
 case 'f':
 filename = optarg; // optarg contains the argument
 break;
 case '?':
 fprintf(stderr, "Unknown option: %c\n", optopt);
 return 1;
 }
 }

 if (verbose) {
 printf("Verbose mode enabled\n");
 }

 if (filename) {
 printf("Filename: %s\n", filename);
 } else {
 printf("No filename specified\n");
 }

 // Process remaining non-option arguments
 printf("Remaining arguments: ");
 for (int i = optind; i < argc; i++) {
 printf("%s ", argv[i]);
 }
 printf("\n");

 return 0;
}

